import re, json, sys

html = open("/home/user/altair_project/chart.html").read()
# Extract the JSON spec embedded in the HTML
m = re.search(r'const spec\s*=\s*(\{.*?\});\s*\n\s*const embedOpt', html, re.DOTALL)
if not m:
    # Try alternative pattern used by newer altair
    m = re.search(r'vegaEmbed\(.*?,\s*(\{.*?\})\s*,\s*\{', html, re.DOTALL)
if not m:
    # Just grab first large JSON object
    start = html.index('{"$schema"')
    depth = 0
    for i, c in enumerate(html[start:], start):
        if c == '{': depth += 1
        elif c == '}':
            depth -= 1
            if depth == 0:
                spec = json.loads(html[start:i+1])
                break
else:
    spec = json.loads(m.group(1))

print("=== Top-level keys:", list(spec.keys()))
assert "vconcat" in spec, "FAIL: no vconcat at top level"
vc = spec["vconcat"]
assert len(vc) == 2, f"FAIL: vconcat has {len(vc)} entries, expected 2"
print("PASS: vconcat has exactly 2 entries")

# Check both entries have area marks
def find_marks(node, found=None):
    if found is None: found = []
    if isinstance(node, dict):
        m = node.get("mark")
        if isinstance(m, str): found.append(m)
        elif isinstance(m, dict): found.append(m.get("type",""))
        for v in node.values():
            find_marks(v, found)
    elif isinstance(node, list):
        for item in node:
            find_marks(item, found)
    return found

upper_marks = find_marks(vc[0])
lower_marks = find_marks(vc[1])
print("Upper marks:", upper_marks)
print("Lower marks:", lower_marks)
