assert "area" in lower_marks, "FAIL: lower entry has no area mark"
print("PASS: both vconcat entries contain area marks")

# Check lower entry has selection_interval with encodings:['x']
def find_selections(node, found=None):
    if found is None: found = []
    if isinstance(node, dict):
        params = node.get("params", [])
        for p in params:
            sel = p.get("select", {})
            if isinstance(sel, dict) and sel.get("type") == "interval":
                found.append(sel)
        for v in node.values():
            find_selections(v, found)
    elif isinstance(node, list):
        for item in node:
            find_selections(item, found)
    return found

lower_sels = find_selections(vc[1])
