    "FAIL: lower entry has no interval selection restricted to x"
print("PASS: lower entry has selection_interval with encodings=['x']")

# Check upper entry x-scale domain references brush param
def find_x_domains(node, found=None):
    if found is None: found = []
    if isinstance(node, dict):
        enc = node.get("encoding", {})
        x_enc = enc.get("x", {})
        sc = x_enc.get("scale", {})
        dom = sc.get("domain", {})
        if isinstance(dom, dict) and "param" in dom:
            found.append(dom["param"])
        for v in node.values():
            if isinstance(v, (dict, list)):
                find_x_domains(v, found)
    elif isinstance(node, list):
        for item in node:
            find_x_domains(item, found)
    return found

upper_domains = find_x_domains(vc[0])
print("Upper x domain params:", upper_domains)
assert len(upper_domains) > 0, "FAIL: upper entry x encoding has no brush domain reference"
print("PASS: upper entry x encoding scale.domain references brush param")

# Get brush param name from lower entry
def get_param_names(node, found=None):
    if found is None: found = []
    if isinstance(node, dict):
        for p in node.get("params", []):
            if "name" in p:
                found.append(p["name"])
        for v in node.values():
            if isinstance(v, (dict, list)):
                get_param_names(v, found)
    elif isinstance(node, list):
        for item in node:
            get_param_names(item, found)
    return found

lower_param_names = get_param_names(vc[1])
print("Lower param names:", lower_param_names)
brush_name = upper_domains[0]
assert brush_name in lower_param_names, \
    f"FAIL: brush name '{brush_name}' not found in lower params {lower_param_names}"
print(f"PASS: brush name '{brush_name}' matches between upper domain and lower param")

# Check upper entry has rule mark + transform_aggregate/window with max(price) + filter ref brush
def find_rules_and_transforms(node, found=None):
    if found is None: found = {"rules": [], "aggregates": [], "windows": [], "filters": []}
    if isinstance(node, dict):
        m = node.get("mark")
        mark_type = m if isinstance(m, str) else (m.get("type","") if isinstance(m, dict) else "")
        if mark_type == "rule":
            found["rules"].append(node)
        transforms = node.get("transform", [])
        for t in transforms:
            if "aggregate" in t:
                for agg in t["aggregate"]:
                    if agg.get("op") == "max" and "price" in agg.get("field",""):
                        found["aggregates"].append(agg)
            if "window" in t:
                for win in t["window"]:
                    if win.get("op") == "max" and "price" in win.get("field",""):
                        found["windows"].append(win)
            if "filter" in t:
                flt = t["filter"]
                flt_str = json.dumps(flt)
                if brush_name in flt_str:
                    found["filters"].append(flt)
        for v in node.values():
            if isinstance(v, (dict, list)):
                find_rules_and_transforms(v, found)
    elif isinstance(node, list):
        for item in node:
            find_rules_and_transforms(item, found)
    return found

upper_rt = find_rules_and_transforms(vc[0])
print("Upper rules:", len(upper_rt["rules"]))
print("Upper max aggregates:", upper_rt["aggregates"])
print("Upper max windows:", upper_rt["windows"])
print("Upper brush filters:", upper_rt["filters"])
assert len(upper_rt["rules"]) > 0, "FAIL: upper entry has no rule mark"
assert len(upper_rt["aggregates"]) > 0 or len(upper_rt["windows"]) > 0, \
    "FAIL: upper entry has no aggregate/window transform computing max(price)"
assert len(upper_rt["filters"]) > 0, \
    "FAIL: upper entry has no transform_filter referencing the brush"
print("PASS: upper entry contains rule + max transform + brush filter")

print("\n=== ALL STRUCTURAL CHECKS PASSED ===")
